glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
in vec2 a_uv0;
out vec4 v_color;
out vec2 v_uv0;
void main () {
  vec4 pos = vec4(a_position, 1.0);
  #if CC_USE_MODEL
  pos = cc_matViewProj * cc_matWorld * pos;
  #else
  pos = cc_matViewProj * pos;
  #endif
  v_uv0 = a_uv0;
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 v_color;
in vec2 v_uv0;
uniform sampler2D texture;
uniform Constant {
  float blurSize;
};
void main () {
  vec2 d = vec2(blurSize, blurSize);
  vec4 c = vec4(0.0);
  c += texture(texture, v_uv0 + d * vec2(-1.0, -1.0));
  c += texture(texture, v_uv0 + d * vec2(0.0, -1.0));
  c += texture(texture, v_uv0 + d * vec2(1.0, -1.0));
  c += texture(texture, v_uv0 + d * vec2(-1.0, 0.0));
  c += texture(texture, v_uv0);
  c += texture(texture, v_uv0 + d * vec2(1.0, 0.0));
  c += texture(texture, v_uv0 + d * vec2(-1.0, 1.0));
  c += texture(texture, v_uv0 + d * vec2(0.0, 1.0));
  c += texture(texture, v_uv0 + d * vec2(1.0, 1.0));
  c = c / 9.0 * v_color;
  ALPHA_TEST(c);
  gl_FragColor = c;
}

